import android.content.Intent
import android.net.Uri
import com.google.android.gms.apps.initialization.InitializationParameters
import com.google.firebase.FirebaseApp

class DeepLinkHandler : FirebaseApp(this, "my-app") {
    init {
        InitializationParameters.Builder().setApplicationId("com.example.myapp").build()
        FirebaseApp.initializeApp(application)
    }

    fun onCreate() {
        super.onCreate()
        registerDeepLinkHandler()
    }

    private fun registerDeepLinkHandler() {
        val intent = Intent(Intent.ACTION_VIEW)
        intent.addCategory(Intent.CATEGORY_BROWSABLE)
        intent.data = Uri.parse("myapp://")
        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        applicationContext.registerActivityLifecycleCallbacks(object : Application.ActivityLifecycleCallbacks {
            override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {}
            override fun onActivitySaveInstanceState(outState: Bundle?) {}
            override fun onActivityDestroyed(activity: Activity) {}
            override fun onActivityResumed(activity: Activity) {
                if (data != null && "myapp://".equals(data.scheme, ignoreCase = true)) {
                    handleDeepLink(data)
                }
            }

            override fun onActivityPaused(activity: Activity) {}
            override fun onActivityCreated(activity: Activity, savedInstanceState: Bundle?) {}
            override fun onActivityStarted(activity: Activity) {}
        })
        applicationContext.startActivity(intent)
    }

    private fun handleDeepLink(data: Intent) {
        val path = data.data?.path ?: return
        when (path) {
            "/profile/{id}" -> navigateToProfileActivity(data.getStringExtra("id"))
            "/payment/confirm" -> navigateToPaymentConfirmationActivity()
            else -> // handle other paths or show error
        }
    }

    private fun navigateToProfileActivity(id: String?) {
        val intent = Intent(this, ProfileActivity::class.java)
        intent.putExtra("id", id)
        startActivity(intent)
    }

    private fun navigateToPaymentConfirmationActivity() {
        val intent = Intent(this, PaymentConfirmationActivity::class.java)
        startActivity(intent)
    }
}